import React, { useState, useEffect } from "react";

function TenantForm({ onSubmit, initialData }) {
  const [name, setName] = useState("");
  const [adminEmail, setAdminEmail] = useState("");

  useEffect(() => {
    if (initialData) {
      setName(initialData.name);
      setAdminEmail(initialData.adminEmail);
    }
  }, [initialData]);

  return (
    <form onSubmit={(e) => { e.preventDefault(); onSubmit({ name, adminEmail }); }}>
      <input value={name} onChange={(e) => setName(e.target.value)} placeholder="Tenant Name" required />
      <input value={adminEmail} onChange={(e) => setAdminEmail(e.target.value)} placeholder="Email" required />
      <button type="submit">Save</button>
    </form>
  );
}

export default TenantForm;
